#!/usr/bin/env bun
/**
 * Review Compression System (IN-002) — Bisect Verification Script
 * 
 * Usage: bun run scripts/review-compression-bisect.ts
 * 
 * Validates each checkpoint in order. Exits with code 1 on first failure.
 * Each step prints PASS/FAIL with details.
 */

import { $ } from 'bun'
import path from 'path'

const ROOT = process.cwd()
const SCHEMAS = [
  'docs/schemas/rig.relay.review_manifest.v1.schema.json',
  'docs/schemas/rig.relay.builder_publication_record.v1.schema.json',
  'docs/schemas/rig.relay.verification_record.v1.schema.json',
  'docs/schemas/rig.relay.prepublication_review_cycle.v1.schema.json',
]

let passed = 0
let failed = 0

async function check(label: string, fn: () => Promise<void>) {
  try {
    await fn()
    console.log(`  PASS: ${label}`)
    passed++
  } catch (e) {
    console.log(`  FAIL: ${label}`)
    console.log(`        ${(e as Error).message}`)
    failed++
  }
}

console.log('\n=== Review Compression System — Bisect Verification ===\n')

// Step 1: Schema files exist
console.log('Step 1: Schema files exist')
for (const f of SCHEMAS) {
  const fullPath = path.join(ROOT, f)
  await check(`File exists: ${f}`, async () => {
    const exists = await Bun.file(fullPath).exists()
    if (!exists) throw new Error(`File not found: ${fullPath}`)
  })
}

// Step 2: Schema files are valid JSON
console.log('\nStep 2: Schema files are valid JSON')
for (const f of SCHEMAS) {
  const fullPath = path.join(ROOT, f)
  await check(`Valid JSON: ${f}`, async () => {
    const content = await Bun.file(fullPath).text()
    JSON.parse(content) // throws if invalid
  })
}

// Step 3: Schema files have required metadata
console.log('\nStep 3: Schema files have required metadata')
const requiredTopKeys = ['\$schema', '\$id', 'title', 'description', 'type', 'properties']
for (const f of SCHEMAS) {
  await check(`Schema metadata: ${f}`, async () => {
    const content = await Bun.file(path.join(ROOT, f)).text()
    const schema = JSON.parse(content)
    if (!schema['\$schema']) throw new Error('Missing \$schema')
    if (!schema['\$id']) throw new Error('Missing \$id')
    if (!schema.title) throw new Error('Missing title')
    if (!schema.type || schema.type !== 'object') throw new Error('type must be "object"')
    if (!schema.properties || typeof schema.properties !== 'object') throw new Error('Missing or invalid properties')
    if (!Array.isArray(schema.required)) throw new Error('required must be array')
  })
}

// Step 4: No Python syntax contamination
console.log('\nStep 4: No Python syntax contamination')
const pythonPatterns = ['from __future__', 'import ', 'def ', 'class ', '# ruff:', '# noqa']
for (const f of SCHEMAS) {
  await check(`No Python syntax: ${f}`, async () => {
    const content = await Bun.file(path.join(ROOT, f)).text()
    for (const pat of pythonPatterns) {
      if (content.includes(pat)) {
        throw new Error(`File contains Python syntax pattern: '${pat}'`)
      }
    }
  })
}

// Step 5: Run weight rubric tests
console.log('\nStep 5: Weight rubric tests')
await check('Weight rubric test suite', async () => {
  const result = await $`cd packages/opencode && bun test test/review-compression/weight-rubric.test.ts`.nothrow().quiet()
  if (result.exitCode !== 0) {
    throw new Error(`Weight rubric tests failed (exit code ${result.exitCode})`)
  }
})

// Step 6: Run comparison engine tests
console.log('\nStep 6: Comparison engine tests')
await check('Comparison engine test suite', async () => {
  const result = await $`cd packages/opencode && bun test test/review-compression/comparison-engine.test.ts`.nothrow().quiet()
  if (result.exitCode !== 0) {
    throw new Error(`Comparison engine tests failed (exit code ${result.exitCode})`)
  }
})

// Step 7: Run schema validation tests
console.log('\nStep 7: Schema validation tests')
await check('Schema validation test suite', async () => {
  const result = await $`cd packages/opencode && bun test test/review-compression/schema-validate.test.ts`.nothrow().quiet()
  if (result.exitCode !== 0) {
    throw new Error(`Schema validation tests failed (exit code ${result.exitCode})`)
  }
})

// Step 8: Run integration tests
console.log('\nStep 8: Integration test suite')
await check('Integration test suite', async () => {
  const result = await $`cd packages/opencode && bun test test/review-compression/manifest-integration.test.ts`.nothrow().quiet()
  if (result.exitCode !== 0) {
    throw new Error(`Integration tests failed (exit code ${result.exitCode})`)
  }
})

// Step 9: Run existing snapshot tests for regression
console.log('\nStep 9: Existing snapshot regression tests')
await check('Snapshot snapshot.test.ts', async () => {
  const result = await $`cd packages/opencode && bun test test/snapshot/snapshot.test.ts`.nothrow().quiet()
  if (result.exitCode !== 0) {
    throw new Error(`Snapshot tests regressed (exit code ${result.exitCode})`)
  }
})

// Summary
console.log(`\n=== Results: ${passed} passed, ${failed} failed ===\n`)
process.exit(failed > 0 ? 1 : 0)
